-- LANGUAGES (IDs 1-50)
-- =============================================
INSERT INTO languages (slug, name, description, language_family, language_status, speakers_count, script, writing_system, dialects, is_official, is_lingua_franca, region_type, province, origin_history, cultural_significance, endangered_details, preservation_efforts, created_at) VALUES

('nepali', 'Nepali', 'Official language of Nepal and lingua franca of the nation. Belongs to the Indo-Aryan language family and is written in Devanagari script.', 'INDO_ARYAN', 'SAFE', 17000000, 'Devanagari', 'Devanagari', 'Khas, Palpa, Doteli, Baitadi, Dadeldhura, Jumli', true, true, 'HILL', 'All', 'Evolved from Sanskrit through Prakrit and Apabhramsha. Khas language became dominant during Shah dynasty unification in 18th century.', 'National language and primary medium of education, government, and media. Represents national identity.', NULL, 'Constitutional protection as national language. Used in education and governance.', NOW()),

('maithili', 'Maithili', 'Second most spoken language in Nepal, predominantly spoken in the Terai region. Has its own historical literary tradition.', 'INDO_ARYAN', 'SAFE', 11000000, 'Devanagari', 'Devanagari', 'Standard Maithili, Tharu-Maithili, Sadani', false, false, 'TERAI', 'Province 2', 'Originated in the Mithila region. Rich literary tradition dating to 14th century with poets like Vidyapati.', 'Bearer of Mithila cultural heritage including Madhubani painting tradition and Mithila cuisine.', NULL, 'Growing literary community. Maithili newspapers and radio programs exist.', NOW()),

('bhojpuri', 'Bhojpuri', 'Widely spoken language of the eastern Terai region with cultural connections to Bihar and Uttar Pradesh.', 'INDO_ARYAN', 'SAFE', 6000000, 'Devanagari', 'Devanagari', 'Standard Bhojpuri, Tharu-Bhojpuri', false, false, 'TERAI', 'Province 2', 'Part of the Eastern Hindi group. Significant diaspora community worldwide.', 'Associated with vibrant folk music and Chhath Puja celebrations.', NULL, 'Active media presence with Bhojpuri songs and films.', NOW()),

('tharu', 'Tharu', 'Language of the Tharu people indigenous to the Terai lowlands. Several distinct dialect groups exist.', 'INDO_ARYAN', 'SAFE', 1500000, 'Devanagari', 'Devanagari', 'Rana Tharu, Kathariya, Morangiya, Dangaura, Chitwaniya', false, false, 'TERAI', 'Lumbini', 'Ancient language of the Terai plains. Tharu people claim descent from Rajput warriors who migrated centuries ago.', 'Central to Tharu identity and their unique stick dance tradition.', NULL, 'Community-led language preservation programs in Dang and Banke.', NOW()),

('tamang', 'Tamang', 'Tibeto-Burman language spoken by the Tamang people across the middle hills of Nepal.', 'SINO_TIBETAN', 'SAFE', 1500000, 'Devanagari', 'Devanagari', 'Eastern Tamang, Western Tamang, Northeastern Tamang', false, false, 'HILL', 'Bagmati', 'Ancient Tibeto-Burman language. Tamang script was developed in 20th century but Devanagari is widely used.', 'Language of the largest hill indigenous group. Essential for oral history and Tamang Selo music.', NULL, 'Tamang language schools and cultural programs in Kavrepalanchok and Sindhupalchok.', NOW()),

('nepal-bhasa', 'Nepal Bhasa (Newari)', 'Historical language of the Kathmandu Valley with a rich literary and cultural tradition.', 'SINO_TIBETAN', 'SAFE', 1000000, 'Ranjana', 'Devanagari', 'Kathmandu, Bhaktapur, Patan dialects', false, false, 'URBAN', 'Bagmati', 'One of the oldest Tibeto-Burman languages. Has literature dating to 13th century. Used as court language of Malla kingdoms.', 'Language of Newar civilization. Used in Buddhist and Hindu rituals, festivals, and traditional governance.', NULL, 'Newar cultural organizations run language classes. Growing media presence.', NOW()),

('bajjika', 'Bajjika', 'Dialect of Maithili spoken in the western Terai and bordering Indian regions.', 'INDO_ARYAN', 'SAFE', 800000, 'Devanagari', 'Devanagari', 'Bajjika sub-dialects', false, false, 'TERAI', 'Province 2', 'Dialect cluster within the Mithila cultural zone.', 'Associated with rural Terai culture, folk songs, and agricultural festivals.', NULL, 'Spoken widely but limited institutional support.', NOW()),

('magar', 'Magar', 'Tibeto-Burman language of the Magar people, one of the largest indigenous groups.', 'SINO_TIBETAN', 'SAFE', 700000, 'Devanagari', 'Devanagari', 'Western Magar, Kham Magar', false, false, 'HILL', 'Gandaki', 'One of the oldest Tibeto-Burman languages in Nepal. Magars historically served as Gorkha soldiers.', 'Language carries oral epics, folk songs, and the Tamang/Magar cultural narrative.', NULL, 'Magar cultural associations promote the language through literature and events.', NOW()),

('awadhi', 'Awadhi', 'Language spoken in the western Terai with cultural ties to the Awadh region of India.', 'INDO_ARYAN', 'SAFE', 600000, 'Devanagari', 'Devanagari', 'Standard Awadhi', false, false, 'TERAI', 'Lumbini', 'Descended from Central Indo-Aryan. Rich tradition of bhakti literature.', 'Language of Tulsidas and the Ramcharitmanas tradition. Connected to Tharu and other Terai communities.', NULL, 'Maintained through oral tradition and cultural practices.', NOW()),

('rai-languages', 'Rai Languages', 'Collective term for numerous Kiranti languages spoken by Rai people across eastern hills.', 'SINO_TIBETAN', 'VULNERABLE', 600000, 'Devanagari', 'Devanagari', 'Bantawa, Chamling, Kulung, Saam, Rai, Nachhiring, and many more', false, false, 'HILL', 'Koshi', 'Ancient Kiranti languages predating Indo-Aryan migration. Each Rai sub-group has distinct language.', 'Central to Kiranti religion and Mundhum oral tradition. Language of Sakela festival rituals.', NULL, 'Rai literature development programs. Some endangerment from Nepali dominance.', NOW()),

('gurung', 'Gurung', 'Tibeto-Burman language of the Gurung people of central Nepal hills.', 'SINO_TIBETAN', 'SAFE', 500000, 'Devanagari', 'Devanagari', 'Standard Gurung, Tsamang', false, false, 'HILL', 'Gandaki', 'Ancient Tibeto-Burman language. Gurungs served as soldiers in British and Indian armies.', 'Language of Gurung oral tradition, folk songs, and Buddhist rituals.', NULL, 'Gurung cultural associations and diaspora communities maintain the language.', NOW()),

('limbu', 'Limbu', 'Kiranti language of the Limbu people in eastern Nepal with its own historical script.', 'SINO_TIBETAN', 'SAFE', 350000, 'Limbu', 'Devanagari', 'Standard Limbu, Phedape, Chhatthare', false, false, 'HILL', 'Koshi', 'Ancient Kiranti language. Limbu script (Sirijonga) was developed in 19th century.', 'Language of Kiranti Mundhum tradition and Chasok Tangnam festival.', NULL, 'Sirijonga script revival movement. Limbi language in schools in some districts.', NOW()),

('sherpa', 'Sherpa', 'Tibeto-Burman language of the Sherpa people in high Himalayan regions.', 'SINO_TIBETAN', 'VULNERABLE', 200000, 'Tibetan', 'Devanagari', 'Standard Sherpa, Solu Sherpa', false, false, 'HIMALAYAN', 'Province 1', 'Related to Tibetan languages. Sherpas migrated from eastern Tibet several centuries ago.', 'Language of Sherpa Buddhist culture and mountaineering heritage.', NULL, 'Threatened by tourism-driven Nepali and English influence. Schools use Nepali.', NOW()),

('hindi', 'Hindi', 'Indo-Aryan language spoken by Madheshi and other communities with cultural ties to India.', 'INDO_ARYAN', 'SAFE', 200000, 'Devanagari', 'Devanagari', 'Standard Hindi, Bhojpuri-Hindi', false, false, 'TERAI', 'Province 2', 'Standardized form of Hindustani. Widely understood through Indian media.', 'Medium of cultural exchange with India. Bollywood influence significant.', NULL, 'Widely understood through Indian media and education.', NOW()),

('urdu', 'Urdu', 'Language of the Muslim community in Nepal with Perso-Arabic script tradition.', 'INDO_ARYAN', 'SAFE', 200000, 'Perso-Arabic', 'Perso-Arabic', 'Standard Urdu', false, false, 'TERAI', 'Multiple', 'Developed in South Asian Muslim cultural centers. Closely related to Hindi in spoken form.', 'Language of Islamic scholarship and Muslim cultural identity in Nepal.', NULL, 'Madrasas and Muslim cultural organizations maintain the language.', NOW()),

('bengali', 'Bengali', 'Indo-Aryan language spoken in eastern Nepal Terai and by Bengali-origin communities.', 'INDO_ARYAN', 'SAFE', 200000, 'Bengali', 'Devanagari', 'Standard Bengali', false, false, 'TERAI', 'Province 1', 'Eastern Indo-Aryan language with rich literary tradition from Bengal.', 'Connected to Bengali cultural festivals and literary tradition.', NULL, 'Community schools and cultural organizations.', NOW()),

('santhali', 'Santhali', 'Austroasiatic language of the Santhal people in Nepal Terai.', 'OTHER', 'SAFE', 150000, 'Ol Chiki', 'Devanagari', 'Standard Santhali', false, false, 'TERAI', 'Province 1', 'Part of the Munda branch of Austroasiatic family. Ol Chiki script invented in 1925.', 'Language of Santhal folk music, dance (Chhau), and harvest festivals.', NULL, 'Growing use of Ol Chiki script. Cultural organizations active.', NOW()),

('chamling', 'Chamling', 'Kiranti language of the Chamling people in eastern Nepal hills.', 'SINO_TIBETAN', 'VULNERABLE', 100000, 'Devanagari', 'Devanagari', 'Standard Chamling', false, false, 'HILL', 'Koshi', 'Ancient Kiranti language with roots in eastern Nepal.', 'Language of Kirant religious practices and Chamling oral tradition.', NULL, 'Endangered by Nepali and Rai dominance. Limited written materials.', NOW()),

('sunuwar', 'Sunuwar', 'Kiranti language of the Sunuwar (Koche) people in eastern Nepal.', 'SINO_TIBETAN', 'VULNERABLE', 80000, 'Devanagari', 'Devanagari', 'Standard Sunuwar', false, false, 'HILL', 'Province 1', 'Kiranti language with distinct phonological features.', 'Connected to Sunuwar identity and Mundhum oral tradition.', NULL, 'Limited documentation. Community efforts underway.', NOW()),

('thakali', 'Thakali', 'Tibeto-Burman language of the Thakali people from the Kali Gandaki region.', 'SINO_TIBETAN', 'VULNERABLE', 70000, 'Devanagari', 'Devanagari', 'Standard Thakali', false, false, 'HIMALAYAN', 'Gandaki', 'Language of salt-trading Thakali merchants from the Kali Gandaki corridor.', 'Language of Thakali culinary and trade culture. Tiji festival language.', NULL, 'Declining due to Nepali and tourism influence in Mustang corridor.', NOW()),

('rajbanshi', 'Rajbanshi', 'Indo-Aryan language of the Rajbanshi people in eastern Terai and hills.', 'INDO_ARYAN', 'SAFE', 100000, 'Bengali', 'Devanagari', 'Standard Rajbanshi', false, false, 'TERAI', 'Province 1', 'Language of indigenous Rajbanshi communities with historical kingdoms.', 'Language of Bihu festivals and agricultural traditions.', NULL, 'Growing awareness through cultural revival movements.', NOW()),

('chepang', 'Chepang', 'Tibeto-Burman language of the semi-nomadic Chepang people.', 'SINO_TIBETAN', 'VULNERABLE', 50000, 'Devanagari', 'Devanagari', 'Standard Chepang', false, false, 'HILL', 'Bagmati', 'Language of the forest-dwelling Chepang people with minimal outside contact historically.', 'Central to Chepang identity and their unique animistic rituals.', NULL, 'Threatened by displacement and education in Nepali only.', NOW()),

('danuwar', 'Danuwar', 'Tibeto-Burman language of the Danuwar people in the Terai-Hill transition zone.', 'SINO_TIBETAN', 'VULNERABLE', 30000, 'Devanagari', 'Devanagari', 'Standard Danuwar', false, false, 'TERAI', 'Province 1', 'Minor Tibeto-Burman language with declining speaker base.', 'Language of Danuwar fishing and riverine culture.', NULL, 'Rapidly declining. Limited documentation available.', NOW()),

