('hayu', 'Hayu', 'Kiranti language of the Hayu people in central-eastern Nepal hills.', 'SINO_TIBETAN', 'DEFINITELY_ENDANGERED', 10000, 'Devanagari', 'Devanagari', 'Standard Hayu', false, false, 'HILL', 'Province 1', 'Ancient Kiranti language with limited geographic distribution.', 'Language of Hayu religious ceremonies and cultural practices.', NULL, 'Fewer than 10,000 speakers. Children increasingly speak Nepali.', NOW()),

('lepcha', 'Lepcha', 'Sino-Tibetan language with its own unique script, spoken near Nepal-India-Sikkim borders.', 'SINO_TIBETAN', 'DEFINITELY_ENDANGERED', 10000, 'Lepcha', 'Lepchabel', 'Standard Lepcha', false, false, 'HIMALAYAN', 'Province 1', 'Ancient language with the Lepcha script dating to 17th century or earlier.', 'Language of Lepcha cultural heritage and Buddhist traditions in the Kanchenjunga region.', NULL, 'Critically low number of fluent speakers. Script preservation efforts ongoing.', NOW()),

('kusunda', 'Kusunda', 'Language isolate with no known relatives. Spoken by fewer than 40 people in western Nepal.', 'KUSUNDA', 'CRITICALLY_ENDANGERED', 32, 'None', 'None', 'None', false, false, 'HILL', 'Gandaki', 'One of the world great mysteries - a language isolate with no known linguistic relatives. Possibly pre-Tibeto-Burman and pre-Indo-Aryan.', 'Irreplaceable linguistic heritage. Represents potential pre-Neolithic language layer of South Asia.', 'Fewer than 40 fluent speakers remain. Most are elderly. Language could die within a generation.', 'Documentation by linguists from Tribhuvan University. International academic interest.', NOW()),

