('chhintang', 'Chhintang', 'Kiranti language of the Chhintang people in eastern Nepal.', 'SINO_TIBETAN', 'SEVERELY_ENDANGERED', 2000, 'Devanagari', 'Devanagari', 'Standard Chhintang', false, false, 'HILL', 'Province 1', 'One of the smallest Kiranti languages by speaker population.', 'Language of Chhintang identity and rituals.', NULL, 'Severely endangered. Most speakers are elderly.', NOW()),

('vayu', 'Vayu', 'Kiranti language of the Vayu people in eastern Nepal.', 'SINO_TIBETAN', 'DEFINITELY_ENDANGERED', 2000, 'Devanagari', 'Devanagari', 'Standard Vayu', false, false, 'HILL', 'Province 1', 'Ancient Kiranti language with declining speaker base.', 'Connected to traditional Vayu religious practices.', NULL, 'Endangered. Younger generation shifting to Nepali.', NOW()),

('lhomi', 'Lhomi', 'Tibeto-Burman language of the Lhomi people in high-altitude regions.', 'SINO_TIBETAN', 'DEFINITELY_ENDANGERED', 2000, 'Tibetan', 'Devanagari', 'Standard Lhomi', false, false, 'HIMALAYAN', 'Province 1', 'Language of high-altitude communities with Tibetan cultural connections.', 'Connected to Buddhist rituals and pastoral life in high Himalayas.', NULL, 'Declining due to low population and modernization.', NOW()),

('nar-phu', 'Nar-Phu', 'Tibeto-Burman language of the Nar and Phu valley communities.', 'SINO_TIBETAN', 'DEFINITELY_ENDANGERED', 1000, 'Tibetan', 'Devanagari', 'Nar dialect, Phu dialect', false, false, 'HIMALAYAN', 'Gandaki', 'Language of isolated valleys in the Manang district. Highly conservative linguistically.', 'Language of unique high-altitude Buddhist culture.', NULL, 'Very small speaker population in remote valleys.', NOW()),

('gyalsumdo', 'Gyalsumdo', 'Tibeto-Burman language of the Gyalsumdo people in the Manaslu region.', 'SINO_TIBETAN', 'SEVERELY_ENDANGERED', 500, 'Tibetan', 'Devanagari', 'Standard Gyalsumdo', false, false, 'HIMALAYAN', 'Gandaki', 'Language of an extremely small community in the Manaslu Conservation Area.', 'Represents unique linguistic heritage of the Manaslu region.', NULL, 'Critically few speakers. Nearly extinct.', NOW()),

('kham-magar', 'Kham Magar', 'Western Magar dialect cluster spoken in remote hill areas of western Nepal.', 'SINO_TIBETAN', 'VULNERABLE', 40000, 'Devanagari', 'Devanagari', 'Kham dialects', false, false, 'HILL', 'Gandaki', 'Ancient dialect cluster distinct from standard Magar.', 'Language of Kham cultural traditions and oral literature.', NULL, 'Faces pressure from standard Magar and Nepali.', NOW()),

