-- =============================================
-- ETHNIC GROUPS (IDs 1-50, language_id references Languages above)
-- =============================================
INSERT INTO ethnic_groups (slug, name, description, population_estimate, language_id, region_type, province, sub_region, traditional_occupation, social_structure, religion, customs, rituals, festivals, is_indigenous, is_deprived, origin, migration_history, created_at) VALUES

('chhettri', 'Chhettri', 'Largest ethnic group in Nepal. Traditionally Kshatriya caste engaged in agriculture and military service.', 4398000, 1, 'HILL', 'Multiple', 'Pan-Nepal hills', 'Agriculture, Military service', 'Caste system - Kshatriya varna', 'Hindu', 'Dashain and Tihar are the most important festivals. Strong family bonds and patrilineal descent.', 'Navratri worship, Jamara growing, Tikka ceremony', 'Dashain, Tihar, Maghe Sankranti', true, false, 'Descended from Khas people of western Nepal hills. Rose to prominence during Gorkha unification.', 'Migrated across Nepal during Shah dynasty expansion. Now present in all hill districts.', NOW()),

('brahman-hill', 'Brahman (Hill)', 'Hill Brahmin community serving as priests and scholars. Second largest group in Nepal.', 3225000, 1, 'HILL', 'Multiple', 'Pan-Nepal hills', 'Priesthood, Agriculture, Teaching', 'Caste system - Brahmin varna', 'Hindu', 'Strict vegetarianism in many families. Sacred thread ceremony. Sandhya prayer rituals.', 'Hawan/puja rituals, Brahmin marriage ceremonies', 'Dashain, Tihar, Shivaratri, Janai Purnima', true, false, 'Descended from Vedic Brahmin lineage. Settled in Nepal hills for millennia.', 'Historically established in Kathmandu Valley and western hills. Spread across all hill regions.', NOW()),

('magar', 'Magar', 'One of the largest indigenous groups with a distinct Tibeto-Burman language and rich oral traditions.', 1622000, 8, 'HILL', 'Gandaki', 'Western and Central hills', 'Agriculture, Military service', 'Tribal system with village councils', 'Hindu/Buddhist syncretism', 'Strong community bonds through Guthi system. Traditional warrior culture.', ' ancestor worship, shamanic rituals', 'Maghe Sankranti, Dashain, Tihar', true, false, 'Ancient Tibeto-Burman people of central Nepal hills. Historically served as Gorkha soldiers.', 'Primarily inhabit Gandaki and Dhaulagiri regions. Migrated to urban areas in modern times.', NOW()),

('tharu', 'Tharu', 'Indigenous people of the Terai lowlands with unique cultural traditions and stick dance.', 1533000, 4, 'TERAI', 'Lumbini', 'Dang, Banke, Kailali, Rupandehi', 'Agriculture, Fishing, Forest collection', 'Clan-based tribal system', 'Hindu/Animist syncretism', 'Joint family system. Traditional Tharu houses with mud plaster art. Strong forest connection.', 'Jitiya ritual, Bhuiya puja (earth worship)', 'Jitiya, Maghi, Holi, Govardhan Puja', true, false, 'Claim descent from Rajput warriors who fled to Terai to escape Mughal invasions.', 'Ancient inhabitants of Terai. Various Tharu sub-groups across the Terai belt.', NOW()),

('tamang', 'Tamang', 'Largest indigenous hill group with a strong Buddhist cultural tradition and Tamang Selo music.', 1539000, 5, 'HILL', 'Bagmati', 'Central and Eastern hills', 'Agriculture, Porter service, Masonry', 'Tribal system with Lama religious leaders', 'Buddhist/Tengriism', 'Buddhist Lama ceremonies. Traditional Tamang settlements on hilltops.', 'Lama priest rituals, Buddhist prayer ceremonies', 'Tamang Lhosar, Dashain, Tihar', true, false, 'Ancient Tibeto-Burman people. Tamang means horse-people in their language.', 'Historically inhabited central Nepal hills around Kathmandu Valley rim.', NOW()),

('newar', 'Newar', 'Indigenous people of the Kathmandu Valley with a highly developed urban civilization and artisan traditions.', 1321000, 6, 'URBAN', 'Bagmati', 'Kathmandu Valley', 'Trade, Metalwork, Pottery, Weaving', 'Complex caste and clan system', 'Buddhist/Hindu dual tradition', 'Elaborate lifecycle rituals. Guthi land system for community festivals. Distinct architecture.', 'Ihi (bel marriage), Bara Tayegu, death rituals', 'Indra Jatra, Yomari Punhi, Bisket Jatra, Machhindranath Jatra', false, false, 'Descended from ancient Kathmandu Valley inhabitants. Developed Newar civilization over 2000+ years.', 'Indigenous to Kathmandu Valley. Never migrated en masse from elsewhere.', NOW()),

